const d = $input.first().json;
const pwin = d.pwin_data || [];
const actions = d.action_data || [];
const weights = d.current_weights || [];
const winRate = d.win_rate_data || {};

const system = `You are GDA Command's calibration engine. Analyze BD performance feedback and output updated scoring weights as JSON.
Current pwin weights: ${JSON.stringify(weights.filter(w=>w.weight_key.startsWith('pwin.')))}
Rules: pwin weights must sum to 1.0. Max adjustment ±0.05 per cycle. Action/briefing boosts: 0.5-2.0. Return ONLY valid JSON, no markdown.`;

const user = `FEEDBACK (90 days):
Win Rate: ${winRate.win_rate||'N/A'}% (${winRate.wins||0}W/${winRate.losses||0}L)
Pwin Outcomes: ${JSON.stringify(pwin.slice(0,15))}
Action Completion by Category: ${JSON.stringify(actions)}
All Current Weights: ${JSON.stringify(weights)}

Return this exact JSON structure:
{"weights":[{"key":"pwin.customer_relationship","value":0.25,"delta":0.00,"reasoning":"brief"},{"key":"pwin.technical_solution","value":0.20,"delta":0.00,"reasoning":"brief"},{"key":"pwin.past_performance","value":0.20,"delta":0.00,"reasoning":"brief"},{"key":"pwin.price_competitiveness","value":0.15,"delta":0.00,"reasoning":"brief"},{"key":"pwin.team_composition","value":0.10,"delta":0.00,"reasoning":"brief"},{"key":"pwin.contract_vehicle","value":0.10,"delta":0.00,"reasoning":"brief"},{"key":"briefing.army_relevance","value":1.0,"delta":0.00,"reasoning":"brief"},{"key":"briefing.iew_relevance","value":1.0,"delta":0.00,"reasoning":"brief"},{"key":"briefing.intel_community","value":1.0,"delta":0.00,"reasoning":"brief"},{"key":"actions.capture_priority","value":1.0,"delta":0.00,"reasoning":"brief"},{"key":"actions.risk_priority","value":1.0,"delta":0.00,"reasoning":"brief"},{"key":"actions.competitive_priority","value":0.8,"delta":0.00,"reasoning":"brief"}],"learning_summary":"1-2 sentences on what changed and why","confidence":"low"}`;

return [{ json: { system, user, feedback_count: d.total_feedback_count } }];

const raw = $input.first().json;
const feedbackCount = $('Build Learning Prompt').first().json.feedback_count;
let text = '';
try { text = raw.content[0].text; } catch(e) {}

let parsed = { weights: [], learning_summary: 'No changes', confidence: 'low' };
try {
  const match = text.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : text);
} catch(e) {
  return [{ json: { status: 'parse_error', error: text.slice(0,300), sql: null } }];
}

const weightUpserts = (parsed.weights || []).map(w =>
  `INSERT INTO gda_learned_weights (weight_key, weight_value, confidence, notes, updated_at) VALUES ('${w.key}', ${parseFloat(w.value)||0}, 0.1, '${(w.reasoning||'').replace(/'/g,"''")}', NOW()) ON CONFLICT (weight_key) DO UPDATE SET weight_value=${parseFloat(w.value)||0}, confidence=LEAST(gda_learned_weights.confidence+0.05,1.0), notes='${(w.reasoning||'').replace(/'/g,"''")}', updated_at=NOW();`
).join('\n');

const logEntry = `INSERT INTO gda_intelligence_log (category, finding, source, agency, timestamp) VALUES ('learning', '${parsed.learning_summary.replace(/'/g,"''").slice(0,500)}', 'learning-engine', 'internal', NOW());`;

return [{ json: {
  sql: weightUpserts + '\n' + logEntry,
  summary: parsed.learning_summary,
  confidence: parsed.confidence,
  weight_count: (parsed.weights||[]).length,
  feedback_count: feedbackCount,
  computed_at: new Date().toISOString()
} }];
